using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for inline primitive combinations ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge/error cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidQuantityData))]
    public void CalculateTotal_NegativeQuantity_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidQuantityData =>
    [
        (10m, -1, 0.1m),
        (5m, -100, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidPriceData))]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidPriceData =>
    [
        (-1m, 5, 0.1m),
        (-0.01m, 1, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidTaxRateData))]
    public void CalculateTotal_InvalidTaxRate_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidTaxRateData =>
    [
        (10m, 1, -0.01m),
        (10m, 1, 1.01m),
    ];

    // --- ApplyDiscount: DataRow for common discount scenarios ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(99.99, 50.0, 49.995, DisplayName = "50% off fractional price")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with TestDataRow for named invalid cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<TestDataRow<(decimal price, decimal discountPercent)>> InvalidDiscountData =>
    [
        new((100m, -1m)) { DisplayName = "Negative discount" },
        new((100m, 101m)) { DisplayName = "Discount exceeds 100%" },
        new((50m, -0.01m)) { DisplayName = "Slightly negative discount" },
    ];

    // --- FormatPrice: DataRow for string output verification ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(0.50, "€", "€0.50")]
    [DataRow(1000.00, "£", "£1000.00")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

